import React from 'react'
import './contact.css';

const Contact = () => {
  return (
    <section className="contact container section">
      <h2 className="section__title">Get in Touch</h2>

      <div className="contact__container grid">
        <div className="contact__info">
          h3.contact
        </div>
      </div>
    </section>
  )
}

export default Contact
